// SWFL business news landing pages. The flow scrapes the landing page so
// fresh article links are picked up — no per-article URL discovery in v1.
const sources = [
  'https://gulfshoresbusiness.com',
  'https://www.naplesnews.com/business/',
  'https://www.news-press.com/business/',
  'https://www.businessobserverfl.com',
  'https://www.winknews.com/category/local/business/'
];
return sources.map(url => ({ json: { url } }));

// Flatten every scraped page into one NDJSON payload. Dedupe within the
// batch by URL — landing pages occasionally re-render the same article in
// the next-day window.
const now      = new Date();
const iso      = now.toISOString();
const yyyy     = String(now.getUTCFullYear());
const mm       = String(now.getUTCMonth() + 1).padStart(2, '0');
const dd       = String(now.getUTCDate()).padStart(2, '0');
const seen     = new Set();
const articles = [];
for (const item of items) {
  const data     = item.json?.data ?? item.json;
  const md       = data?.markdown ?? '';
  const metadata = data?.metadata ?? {};
  const sourceUrl = metadata.sourceURL ?? metadata.url ?? item.json?.url ?? null;
  const title     = metadata.title ?? null;
  const published = metadata.publishedTime ?? metadata.article_published_time ?? null;
  const domain    = sourceUrl ? new URL(sourceUrl).host : null;
  if (!sourceUrl || seen.has(sourceUrl)) continue;
  seen.add(sourceUrl);
  articles.push({
    url:           sourceUrl,
    title,
    published_date: published,
    content_md:    md,
    source_domain: domain,
    _ingested_at:  iso
  });
}
if (articles.length === 0) {
  throw new Error('Flow 4: zero articles after dedupe — investigate.');
}
const ndjson = articles.map(a => JSON.stringify(a)).join('\n') + '\n';
const bytes  = Buffer.byteLength(ndjson, 'utf-8');
const path   = `news/year=${yyyy}/month=${mm}/day=${dd}/run-${iso}.ndjson`;
return [{
  json: {
    bucket:    'lake-tier1',
    path,
    full_id:   `lake-tier1/${path}`,
    vintage:   `${yyyy}-${mm}-${dd}`,
    byte_size: bytes,
    body:      ndjson,
    article_count: articles.length
  }
}];
